input.command:
kubectl exec -n mongodb mongodb-replica-0 -- bash -c 'cat > /tmp/setup_admin.js << '"'"'EOF'"'"'
db = db.getSiblingDB("admin");
db.createUser({
  user: "admin",
  pwd: "admin123password",
  roles: [{ role: "root", db: "admin" }]
});
print("Admin user created");
EOF'

# Patch StatefulSet to remove --auth and --keyFile temporarily
kubectl patch sts mongodb-replica -n mongodb --type='json' -p='[
  {"op": "replace", "path": "/spec/template/spec/containers/0/command", "value": ["mongod", "--replSet", "mongodb-replica", "--bind_ip_all"]}
]' 2>&1

kubectl exec -n mongodb mongodb-replica-1 -- bash -c 'cat > /tmp/setup_users.js << '"'"'JSEOF'"'"'
// Create admin user
db = db.getSiblingDB("admin");
db.createUser({
  user: "admin",
  pwd: "admin123password",
  roles: [{ role: "root", db: "admin" }]
});
print("admin user created");

// Create app-user with readWrite on appdb
db.getSiblingDB("appdb").createUser({
  user: "app-user",
  pwd: "app123password",
  roles: [{ role: "readWrite", db: "appdb" }]
});
print("app-user created");

// Create reportingRole on appdb with read on appdb.reports (for aggregate)
db.getSiblingDB("appdb").createRole({
  role: "reportingRole",
  privileges: [
    {
      resource: { db: "appdb", collection: "reports" },
      actions: ["find", "aggregate", "listIndexes", "collStats", "dbStats", "listCollections"]
    }
  ],
  roles: []
});
print("reportingRole created");

// Create readonly-user with read on appdb and reportingRole
db.getSiblingDB("appdb").createUser({
  user: "readonly-user",
  pwd: "readonly123password",
  roles: [
    { role: "read", db: "appdb" },
    { role: "reportingRole", db: "appdb" }
  ]
});
print("readonly-user created");
print("All done");
JSEOF'
kubectl exec -n mongodb mongodb-replica-1 -- mongosh --quiet /tmp/setup_users.js 2>&1

kubectl exec -n mongodb mongodb-replica-1 -- bash -c 'cat > /tmp/setup_roles.js << '"'"'JSEOF'"'"'
var appdb = db.getSiblingDB("appdb");

// Create reportingRole with correct actions (find enables aggregate)
appdb.createRole({
  role: "reportingRole",
  privileges: [
    {
      resource: { db: "appdb", collection: "reports" },
      actions: ["find", "listIndexes", "listCollections", "collStats", "dbStats"]
    }
  ],
  roles: []
});
print("reportingRole created");

// Create readonly-user with read on appdb and reportingRole
appdb.createUser({
  user: "readonly-user",
  pwd: "readonly123password",
  roles: [
    { role: "read", db: "appdb" },
    { role: "reportingRole", db: "appdb" }
  ]
});
print("readonly-user created");
print("All done");
JSEOF'
kubectl exec -n mongodb mongodb-replica-1 -- mongosh --quiet /tmp/setup_roles.js 2>&1

kubectl patch sts mongodb-replica -n mongodb --type='json' -p='[
  {"op": "replace", "path": "/spec/template/spec/containers/0/command", "value": ["mongod", "--replSet", "mongodb-replica", "--bind_ip_all", "--auth", "--keyFile=/etc/mongo-keyfile/keyfile"]}
]' 2>&1

PRIMARY=mongodb-replica-1

# Verify app-user readWrite on appdb
kubectl exec -n mongodb $PRIMARY -- mongosh "mongodb://app-user:app123password@localhost/appdb" --quiet --eval "
db.testcol.insertOne({x: 1});
var cnt = db.testcol.countDocuments({});
print('app-user insert+read test: count=' + cnt);
db.testcol.drop();
" 2>&1

PRIMARY=mongodb-replica-1

# Seed some data in appdb.reports for readonly-user tests
kubectl exec -n mongodb $PRIMARY -- mongosh "mongodb://admin:admin123password@localhost/appdb" --quiet --eval "
db.reports.insertMany([{title: 'Q1', value: 100}, {title: 'Q2', value: 200}]);
print('Seeded reports: ' + db.reports.countDocuments({}));
" 2>&1

# admin auth is on admin db, appdb uses admin auth
kubectl exec -n mongodb mongodb-replica-1 -- mongosh "mongodb://admin:admin123password@localhost/admin?authSource=admin" --quiet --eval "
var appdb = db.getSiblingDB('appdb');
appdb.reports.insertMany([{title: 'Q1', value: 100}, {title: 'Q2', value: 200}]);
print('Seeded reports: ' + appdb.reports.countDocuments({}));
" 2>&1

# Verify readonly-user: read on appdb, aggregate on appdb.reports
kubectl exec -n mongodb mongodb-replica-1 -- mongosh "mongodb://readonly-user:readonly123password@localhost/appdb?authSource=appdb" --quiet --eval "
// Test read access on appdb
var cnt = db.reports.countDocuments({});
print('readonly-user read count: ' + cnt);

// Test aggregate on appdb.reports
var result = db.reports.aggregate([{\$group: {_id: null, total: {\$sum: '\$value'}}}]).toArray();
print('readonly-user aggregate result: ' + JSON.stringify(result));
" 2>&1

# Verify readonly-user cannot write
kubectl exec -n mongodb mongodb-replica-1 -- mongosh "mongodb://readonly-user:readonly123password@localhost/appdb?authSource=appdb" --quiet --eval "
try {
  db.reports.insertOne({title: 'unauthorized'});
  print('ERROR: write should have been denied');
} catch(e) {
  print('write correctly denied: ' + e.codeName);
}
" 2>&1

# Verify admin still has root access and replica set is healthy
kubectl exec -n mongodb mongodb-replica-1 -- mongosh "mongodb://admin:admin123password@localhost/admin?authSource=admin" --quiet --eval "
var status = rs.status();
print('RS state: ' + status.ok);
print('Members:');
status.members.forEach(function(m) { print('  ' + m.name + ' state=' + m.stateStr); });
" 2>&1

# Final: show all users and roles for confirmation
kubectl exec -n mongodb mongodb-replica-1 -- mongosh "mongodb://admin:admin123password@localhost/admin?authSource=admin" --quiet --eval "
print('=== admin db users ===');
db.getUsers().users.forEach(function(u) { print(u.user + ' roles: ' + JSON.stringify(u.roles)); });
print('=== appdb users and roles ===');
var appdb = db.getSiblingDB('appdb');
appdb.getUsers().users.forEach(function(u) { print(u.user + ' roles: ' + JSON.stringify(u.roles)); });
print('=== appdb custom roles ===');
appdb.getRoles({showPrivileges: true}).forEach(function(r) { print(r.role + ' privileges: ' + JSON.stringify(r.privileges)); });
" 2>&1
